create table dirkspzm32.s_qs_babtec_wee (
    bestellnummer   varchar2(30 char) not null enable,
    bestellposition varchar2(30 char) not null enable,
    artikel         varchar2(30 char) not null enable,
    lieferantennr   varchar2(30 char),
    lieferscheinnr  varchar2(30 char),
    liefertermin    date,
    lieferdatum     date,
    liefermengesoll number(*, 3),
    liefermengeist  number(*, 3),
    bestelldatum    date,
    lteid           varchar2(20 char) not null enable,
    preisproeinheit number(*, 5),
    solltermin      date,
    lagerplatz      varchar2(30 char) not null enable,
    charge          varchar2(60 char),
    me              varchar2(3 char),
    benutzer1       varchar2(60 char),
    benutzer2       varchar2(60 char),
    benutzer3       varchar2(60 char),
    benutzer4       varchar2(60 char),
    benutzer5       varchar2(60 char),
    benutzer6       varchar2(60 char),
    status          varchar2(3 char),
    erstell_datum   date default sysdate,
    bearb_datum     date,
    fehler_code     number(*, 5),
    fehler_text     varchar2(255 char)
);

alter table dirkspzm32.s_qs_babtec_wee
    add constraint pk_s_qs_babtec_wee primary key ( lteid )
        using index enable;

alter table dirkspzm32.s_qs_babtec_wee
    add constraint uk_s_qs_babtec_wee
        unique ( bestellnummer,
                 bestellposition,
                 artikel,
                 lteid )
            using index enable;


